import { defineConfig } from 'astro/config';
import node from '@astrojs/node';
import react from '@astrojs/react';
import tailwind from '@astrojs/tailwind';

export default defineConfig({
  output: 'server',
  adapter: node({
    mode: 'standalone'
  }),
  integrations: [
    react(),
    tailwind()
  ],
  server: {
    port: 4321,
    host: true
  }
});

// User types
export interface User {
  id: number;
  username: string;
  email: string;
  password_hash: string;
  role: 'admin' | 'editor' | 'user';
  display_name: string | null;
  bio: string | null;
  avatar: string | null;
  website: string | null;
  created_at: string;
  updated_at: string;
}

export type SafeUser = Omit<User, 'password_hash'>;

export type UserRole = 'admin' | 'editor' | 'user';

// Post types
export interface Post {
  id: number;
  title: string;
  slug: string;
  content: string;
  excerpt: string | null;
  status: 'draft' | 'published' | 'archived';
  author_id: number;
  view_count: number;
  created_at: string;
  updated_at: string;
  published_at: string | null;
}

export type PostWithAuthor = Post & { author: SafeUser };

export type PostStatus = 'draft' | 'published' | 'archived';

// Tag types
export interface Tag {
  id: number;
  name: string;
  slug: string;
}

// Session types
export interface Session {
  id: number;
  user_id: number;
  token: string;
  expires_at: string;
  created_at: string;
}

// Settings types
export interface Setting {
  id: number;
  key: string;
  value: string | null;
  created_at: string;
  updated_at: string;
}

// API Response types
export interface ApiResponse<T = unknown> {
  success: boolean;
  data?: T;
  error?: string;
  message?: string;
}

// JWT Payload
export interface JWTPayload {
  id: number;
  username: string;
  role: UserRole;
  exp: number;
  iat: number;
}

// Search result
export interface SearchResult {
  id: number;
  title: string;
  slug: string;
  excerpt: string;
  author: SafeUser;
  published_at: string;
}

// Comment types
export interface Comment {
  id: number;
  post_id: number;
  author_id: number | null;
  author_name: string | null;
  author_email: string | null;
  content: string;
  status: 'pending' | 'approved' | 'spam';
  parent_id: number | null;
  created_at: string;
}

import Database from 'better-sqlite3';
import { fileURLToPath } from 'url';
import { dirname, join } from 'path';
import fs from 'fs';

const __filename = fileURLToPath(import.meta.url);
const __dirname = dirname(__filename);

const DB_PATH = process.env.DATABASE_URL || join(process.cwd(), 'data', 'stellar.db');

// Ensure data directory exists
const dataDir = dirname(DB_PATH);
if (!fs.existsSync(dataDir)) {
  fs.mkdirSync(dataDir, { recursive: true });
}

// Create database connection with WAL mode
let db: Database.Database;

try {
  db = new Database(DB_PATH);

  // Enable WAL mode for better concurrency
  db.pragma('journal_mode = WAL');

  // Enable foreign key constraints
  db.pragma('foreign_keys = ON');

  console.log('Database connected successfully:', DB_PATH);
} catch (error) {
  console.error('Failed to connect to database:', error);
  throw error;
}

// Initialize database schema
export function initSchema(): void {
  const schemaPath = join(process.cwd(), 'src', 'db', 'schema.sql');

  if (!fs.existsSync(schemaPath)) {
    console.error('Schema file not found:', schemaPath);
    return;
  }

  const schema = fs.readFileSync(schemaPath, 'utf-8');

  // Split schema into individual statements
  const statements = schema
    .split(';')
    .map(s => s.trim())
    .filter(s => s.length > 0 && !s.startsWith('--'));

  const transaction = db.transaction(() => {
    for (const statement of statements) {
      try {
        db.exec(statement + ';');
      } catch (error) {
        // Ignore errors for existing tables/indexes
        const errorMessage = error instanceof Error ? error.message : String(error);
        if (!errorMessage.includes('already exists')) {
          console.error('Schema error:', errorMessage);
        }
      }
    }
  });

  transaction();
  console.log('Database schema initialized');
}

// Get database instance
export function getDb(): Database.Database {
  return db;
}

// Close database connection
export function closeDb(): void {
  if (db) {
    db.close();
    console.log('Database connection closed');
  }
}

// Helper to run queries safely
export function query<T = unknown>(sql: string, params: unknown[] = []): T[] {
  const stmt = db.prepare(sql);
  return stmt.all(...params) as T[];
}

// Helper to run a single query
export function queryOne<T = unknown>(sql: string, params: unknown[] = []): T | undefined {
  const stmt = db.prepare(sql);
  return stmt.get(...params) as T | undefined;
}

// Helper to run insert/update/delete
export function run(sql: string, params: unknown[] = []): { lastInsertRowid: number | bigint; changes: number } {
  const stmt = db.prepare(sql);
  const result = stmt.run(...params);
  return {
    lastInsertRowid: result.lastInsertRowid,
    changes: result.changes
  };
}

// Transaction helper
export function transaction<T>(fn: () => T): T {
  const tx = db.transaction(fn);
  return tx();
}

import jwt from 'jsonwebtoken';
import bcrypt from 'bcryptjs';
import type { JWTPayload, UserRole, SafeUser, User } from '../types';

const JWT_SECRET = process.env.JWT_SECRET || 'default-secret-change-in-production';
const JWT_EXPIRES_IN = '7d';
const BCRYPT_SALT_ROUNDS = 10;

// Password hashing
export async function hashPassword(password: string): Promise<string> {
  return bcrypt.hash(password, BCRYPT_SALT_ROUNDS);
}

export async function verifyPassword(password: string, hash: string): Promise<boolean> {
  return bcrypt.compare(password, hash);
}

// Password validation
export function validatePassword(password: string): { valid: boolean; errors: string[] } {
  const errors: string[] = [];

  if (password.length < 8) {
    errors.push('Password must be at least 8 characters long');
  }

  if (!/\d/.test(password)) {
    errors.push('Password must contain at least one number');
  }

  return {
    valid: errors.length === 0,
    errors
  };
}

// JWT Token handling
export function generateToken(payload: Omit<JWTPayload, 'exp' | 'iat'>): string {
  return jwt.sign(payload, JWT_SECRET, { expiresIn: JWT_EXPIRES_IN });
}

export function verifyToken(token: string): JWTPayload | null {
  try {
    return jwt.verify(token, JWT_SECRET) as JWTPayload;
  } catch {
    return null;
  }
}

// Extract token from request
export function extractTokenFromHeader(authHeader: string | null): string | null {
  if (!authHeader) return null;

  const parts = authHeader.split(' ');
  if (parts.length === 2 && parts[0].toLowerCase() === 'bearer') {
    return parts[1];
  }

  return null;
}

// Extract token from cookie
export function extractTokenFromCookie(cookieHeader: string | null): string | null {
  if (!cookieHeader) return null;

  const match = cookieHeader.match(/auth_token=([^;]+)/);
  return match ? decodeURIComponent(match[1]) : null;
}

// Safe user (remove password_hash)
export function toSafeUser(user: User): SafeUser {
  const { password_hash, ...safeUser } = user;
  return safeUser as SafeUser;
}

// Role checking
export function hasRole(userRole: UserRole, requiredRole: UserRole): boolean {
  const roleHierarchy: Record<UserRole, number> = {
    user: 1,
    editor: 2,
    admin: 3
  };

  return roleHierarchy[userRole] >= roleHierarchy[requiredRole];
}

export function isAdmin(role: UserRole): boolean {
  return role === 'admin';
}

export function isEditorOrAdmin(role: UserRole): boolean {
  return role === 'admin' || role === 'editor';
}

// Slug generation
export function generateSlug(text: string): string {
  return text
    .toLowerCase()
    .replace(/[^\w\s-]/g, '')
    .replace(/\s+/g, '-')
    .replace(/-+/g, '-')
    .replace(/^-+|-+$/g, '')
    .substring(0, 100);
}

// Generate unique slug with counter if needed
export function generateUniqueSlug(text: string, existingSlugs: string[]): string {
  let slug = generateSlug(text);
  let counter = 1;
  let uniqueSlug = slug;

  while (existingSlugs.includes(uniqueSlug)) {
    uniqueSlug = `${slug}-${counter}`;
    counter++;
  }

  return uniqueSlug;
}

// Date formatting
export function formatDate(date: string | Date): string {
  const d = typeof date === 'string' ? new Date(date) : date;
  return d.toLocaleDateString('en-US', {
    year: 'numeric',
    month: 'long',
    day: 'numeric'
  });
}

export function formatDateTime(date: string | Date): string {
  const d = typeof date === 'string' ? new Date(date) : date;
  return d.toLocaleString('en-US', {
    year: 'numeric',
    month: 'long',
    day: 'numeric',
    hour: '2-digit',
    minute: '2-digit'
  });
}

export function formatRelativeTime(date: string | Date): string {
  const d = typeof date === 'string' ? new Date(date) : date;
  const now = new Date();
  const diffMs = now.getTime() - d.getTime();
  const diffSecs = Math.floor(diffMs / 1000);
  const diffMins = Math.floor(diffSecs / 60);
  const diffHours = Math.floor(diffMins / 60);
  const diffDays = Math.floor(diffHours / 24);

  if (diffSecs < 60) return 'just now';
  if (diffMins < 60) return `${diffMins}m ago`;
  if (diffHours < 24) return `${diffHours}h ago`;
  if (diffDays < 30) return `${diffDays}d ago`;
  return formatDate(d);
}

// RSS date format (RFC 2822)
export function formatRssDate(date: string | Date): string {
  const d = typeof date === 'string' ? new Date(date) : date;
  return d.toUTCString();
}

// Truncate text
export function truncate(text: string, length: number, suffix = '...'): string {
  if (text.length <= length) return text;
  return text.substring(0, length - suffix.length).trim() + suffix;
}

// Strip HTML tags
export function stripHtml(html: string): string {
  return html.replace(/<[^>]*>/g, ' ').replace(/\s+/g, ' ').trim();
}

// Generate excerpt from content
export function generateExcerpt(content: string, maxLength = 200): string {
  const plainText = stripHtml(content);
  return truncate(plainText, maxLength);
}

// Validate email
export function isValidEmail(email: string): boolean {
  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  return emailRegex.test(email);
}

// Validate URL
export function isValidUrl(url: string): boolean {
  try {
    new URL(url);
    return true;
  } catch {
    return false;
  }
}

// Sanitize string for display
export function escapeHtml(text: string): string {
  const div = { '&': '&amp;', '<': '&lt;', '>': '&gt;', '"': '&quot;', "'": '&#x27;' };
  return text.replace(/[&<>"']/g, (char) => div[char as keyof typeof div]);
}

// Parse form data
export function parseFormData(formData: FormData): Record<string, string | File> {
  const data: Record<string, string | File> = {};
  formData.forEach((value, key) => {
    data[key] = value;
  });
  return data;
}

// Build query string
export function buildQueryString(params: Record<string, string | number | boolean | undefined>): string {
  const searchParams = new URLSearchParams();
  Object.entries(params).forEach(([key, value]) => {
    if (value !== undefined) {
      searchParams.append(key, String(value));
    }
  });
  const query = searchParams.toString();
  return query ? `?${query}` : '';
}

import { z } from 'zod';

// User validation schemas
