// Type exports
export type LoginInput = z.infer<typeof loginSchema>;
export type RegisterInput = z.infer<typeof registerSchema>;
export type UpdateProfileInput = z.infer<typeof updateProfileSchema>;
export type ChangePasswordInput = z.infer<typeof changePasswordSchema>;
export type CreatePostInput = z.infer<typeof createPostSchema>;
export type UpdatePostInput = z.infer<typeof updatePostSchema>;
export type SearchInput = z.infer<typeof searchSchema>;
export type CreateCommentInput = z.infer<typeof createCommentSchema>;
export type UpdateSettingsInput = z.infer<typeof updateSettingsSchema>;

// Custom error classes

export class AppError extends Error {
  public statusCode: number;
  public code: string;

  constructor(message: string, statusCode = 500, code = 'INTERNAL_ERROR') {
    super(message);
    this.name = this.constructor.name;
    this.statusCode = statusCode;
    this.code = code;
    Error.captureStackTrace(this, this.constructor);
  }
}

export class ValidationError extends AppError {
  public errors: Array<{ field: string; message: string }>;

  constructor(errors: Array<{ field: string; message: string }>) {
    super('Validation failed', 400, 'VALIDATION_ERROR');
    this.errors = errors;
  }
}

export class AuthenticationError extends AppError {
  constructor(message = 'Authentication required') {
    super(message, 401, 'AUTHENTICATION_ERROR');
  }
}

export class AuthorizationError extends AppError {
  constructor(message = 'Insufficient permissions') {
    super(message, 403, 'AUTHORIZATION_ERROR');
  }
}

export class NotFoundError extends AppError {
  constructor(resource = 'Resource') {
    super(`${resource} not found`, 404, 'NOT_FOUND');
  }
}

export class ConflictError extends AppError {
  constructor(message = 'Resource already exists') {
    super(message, 409, 'CONFLICT');
  }
}

// Error response formatter
export function formatError(error: unknown): { success: false; error: string; code: string; statusCode: number } {
  if (error instanceof AppError) {
    return {
      success: false,
      error: error.message,
      code: error.code,
      statusCode: error.statusCode
    };
  }

  if (error instanceof Error) {
    return {
      success: false,
      error: error.message,
      code: 'INTERNAL_ERROR',
      statusCode: 500
    };
  }

  return {
    success: false,
    error: 'An unknown error occurred',
    code: 'UNKNOWN_ERROR',
    statusCode: 500
  };
}

import { getDb, query, queryOne, run, transaction } from '../../lib/db';
import type { User, SafeUser, CreateUserInput, UpdateUserInput } from '../../types';

const db = getDb();

// Transform user row to safe user (without password_hash)
export function toSafeUser(user: User): SafeUser {
  const { password_hash, ...safe } = user;
  return safe as SafeUser;
}

// Get user by ID
export function getUserById(id: number): User | undefined {
  return queryOne<User>(
    'SELECT * FROM users WHERE id = ?',
    [id]
  );
}

// Get user by username
export function getUserByUsername(username: string): User | undefined {
  return queryOne<User>(
    'SELECT * FROM users WHERE username = ? COLLATE NOCASE',
    [username]
  );
}

// Get user by email
export function getUserByEmail(email: string): User | undefined {
  return queryOne<User>(
    'SELECT * FROM users WHERE email = ? COLLATE NOCASE',
    [email]
  );
}

// Check if username exists
export function usernameExists(username: string): boolean {
  const result = queryOne<{ count: number }>(
    'SELECT COUNT(*) as count FROM users WHERE username = ? COLLATE NOCASE',
    [username]
  );
  return result?.count > 0;
}

// Check if email exists
export function emailExists(email: string): boolean {
  const result = queryOne<{ count: number }>(
    'SELECT COUNT(*) as count FROM users WHERE email = ? COLLATE NOCASE',
    [email]
  );
  return result?.count > 0;
}

// Create new user
export function createUser(userData: {
  username: string;
  email: string;
  password_hash: string;
  display_name?: string | null;
  role?: 'admin' | 'editor' | 'user';
}): User {
  const result = run(
    `INSERT INTO users (username, email, password_hash, display_name, role, created_at, updated_at)
     VALUES (?, ?, ?, ?, ?, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP)`,
    [
      userData.username,
      userData.email,
      userData.password_hash,
      userData.display_name || null,
      userData.role || 'user'
    ]
  );

  const user = getUserById(Number(result.lastInsertRowid));
  if (!user) {
    throw new Error('Failed to create user');
  }
  return user;
}

// Update user
export function updateUser(userId: number, updates: {
  display_name?: string | null;
  bio?: string | null;
  avatar?: string | null;
  website?: string | null;
  email?: string;
}): User | undefined {
  const fields: string[] = [];
  const values: (string | null)[] = [];

  if (updates.display_name !== undefined) {
    fields.push('display_name = ?');
    values.push(updates.display_name);
  }
  if (updates.bio !== undefined) {
    fields.push('bio = ?');
    values.push(updates.bio);
  }
  if (updates.avatar !== undefined) {
    fields.push('avatar = ?');
    values.push(updates.avatar);
  }
  if (updates.website !== undefined) {
    fields.push('website = ?');
    values.push(updates.website);
  }
  if (updates.email !== undefined) {
    fields.push('email = ?');
    values.push(updates.email);
  }

  if (fields.length === 0) return getUserById(userId);

  fields.push('updated_at = CURRENT_TIMESTAMP');
  values.push(userId);

  run(
    `UPDATE users SET ${fields.join(', ')} WHERE id = ?`,
    values
  );

  return getUserById(userId);
}

// Update user password
export function updatePassword(userId: number, newPasswordHash: string): boolean {
  const result = run(
    'UPDATE users SET password_hash = ?, updated_at = CURRENT_TIMESTAMP WHERE id = ?',
    [newPasswordHash, userId]
  );
  return result.changes > 0;
}

// Update user role (admin only)
export function updateUserRole(userId: number, newRole: 'admin' | 'editor' | 'user'): boolean {
  const result = run(
    'UPDATE users SET role = ?, updated_at = CURRENT_TIMESTAMP WHERE id = ?',
    [newRole, userId]
  );
  return result.changes > 0;
}

// Delete user
export function deleteUser(userId: number): boolean {
  const result = run('DELETE FROM users WHERE id = ?', [userId]);
  return result.changes > 0;
}

// List users with pagination
export function listUsers(options: {
  limit?: number;
  offset?: number;
  role?: 'admin' | 'editor' | 'user';
  search?: string;
} = {}): { users: User[]; total: number } {
  const { limit = 20, offset = 0, role, search } = options;

  const conditions: string[] = [];
  const params: (string | number)[] = [];

  if (role) {
    conditions.push('role = ?');
    params.push(role);
  }

  if (search) {
    conditions.push('(username LIKE ? OR email LIKE ? OR display_name LIKE ?)');
    const likePattern = `%${search}%`;
    params.push(likePattern, likePattern, likePattern);
  }

  const whereClause = conditions.length > 0 ? `WHERE ${conditions.join(' AND ')}` : '';

  const users = query<User>(
    `SELECT * FROM users ${whereClause} ORDER BY created_at DESC LIMIT ? OFFSET ?`,
    [...params, limit, offset]
  );

  const countResult = queryOne<{ count: number }>(
    `SELECT COUNT(*) as count FROM users ${whereClause}`,
    params
  );

  return {
    users,
    total: countResult?.count || 0
  };
}

// Get user stats
export function getUserStats(userId: number): {
  totalPosts: number;
  publishedPosts: number;
  draftPosts: number;
  totalViews: number;
} {
  const result = queryOne<{
    total_posts: number;
    published_posts: number;
    draft_posts: number;
    total_views: number;
  }>(`
    SELECT 
      COUNT(*) as total_posts,
      SUM(CASE WHEN status = 'published' THEN 1 ELSE 0 END) as published_posts,
      SUM(CASE WHEN status = 'draft' THEN 1 ELSE 0 END) as draft_posts,
      COALESCE(SUM(view_count), 0) as total_views
    FROM posts
    WHERE author_id = ?
  `, [userId]);

  return {
    totalPosts: result?.total_posts || 0,
    publishedPosts: result?.published_posts || 0,
    draftPosts: result?.draft_posts || 0,
    totalViews: result?.total_views || 0
  };
}

// Import query functions at the bottom to avoid circular dependencies
import { query, queryOne, run } from '../../lib/db';

import type { Post, PostWithAuthor, SafeUser, PostStatus, Tag, SearchResult } from '../../types';
import { generateSlug, generateUniqueSlug } from '../../lib/utils';
import { getDb, query, queryOne, run, transaction } from '../../lib/db';
import { toSafeUser } from './user';

const db = getDb();

// Get post by ID
export function getPostById(id: number): Post | undefined {
  return queryOne<Post>('SELECT * FROM posts WHERE id = ?', [id]);
}

// Get post by slug
export function getPostBySlug(slug: string): Post | undefined {
  return queryOne<Post>('SELECT * FROM posts WHERE slug = ?', [slug]);
}

// Get post with author
export function getPostWithAuthor(idOrSlug: number | string): PostWithAuthor | undefined {
  const column = typeof idOrSlug === 'number' ? 'p.id' : 'p.slug';
  const result = queryOne<Post & SafeUser>(`
    SELECT 
      p.*,
      u.id as author_id, u.username as author_username, u.email as author_email,
      u.role as author_role, u.display_name as author_display_name,
      u.bio as author_bio, u.avatar as author_avatar, u.website as author_website,
      u.created_at as author_created_at, u.updated_at as author_updated_at
    FROM posts p
    JOIN users u ON p.author_id = u.id
    WHERE ${column} = ?
  `, [idOrSlug]);

  if (!result) return undefined;

  const {
    author_id, author_username, author_email, author_role,
    author_display_name, author_bio, author_avatar, author_website,
    author_created_at, author_updated_at,
    ...post
  } = result;

  const author: SafeUser = {
    id: author_id,
    username: author_username,
    email: author_email,
    role: author_role as 'admin' | 'editor' | 'user',
    display_name: author_display_name,
    bio: author_bio,
    avatar: author_avatar,
