// Get tags for a post
export function getPostTags(postId: number): Tag[] {
  return query<Tag>(`
    SELECT t.* FROM tags t
    JOIN post_tags pt ON t.id = pt.tag_id
    WHERE pt.post_id = ?
    ORDER BY t.name
  `, [postId]);
}

